"use strict";(globalThis.webpackChunkmythogen_engine_blog=globalThis.webpackChunkmythogen_engine_blog||[]).push([[7144],{6336(e,t,n){n.r(t),n.d(t,{assets:()=>h,contentTitle:()=>r,default:()=>c,frontMatter:()=>s,metadata:()=>o,toc:()=>l});var a=n(4848),i=n(8453);const s={},r="Chapter 4: Sega's Five-Million-Dollar Mercy",o={id:"GameVictory/\u7b2c\u56db\u7ae0_\u4e16\u5609\u7684\u4e94\u767e\u842c\u7f8e\u5143\u5584\u6b3e_v1",title:"Chapter 4: Sega's Five-Million-Dollar Mercy",description:"In 2025, a machine learning engineer complained on his company's Slack: training a mid-sized language model requires eight NVIDIA H100s running for three weeks. One H100 costs over $30,000. His company waited in line for six months just to get the shipment. Every company in the world that wants to do AI is waiting in that exact same line.",source:"@site/i18n/en/docusaurus-plugin-content-docs/current/GameVictory/\u7b2c\u56db\u7ae0_\u4e16\u5609\u7684\u4e94\u767e\u842c\u7f8e\u5143\u5584\u6b3e_v1.md",sourceDirName:"GameVictory",slug:"/GameVictory/\u7b2c\u56db\u7ae0_\u4e16\u5609\u7684\u4e94\u767e\u842c\u7f8e\u5143\u5584\u6b3e_v1",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u56db\u7ae0_\u4e16\u5609\u7684\u4e94\u767e\u842c\u7f8e\u5143\u5584\u6b3e_v1",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{},sidebar:"docs",previous:{title:"\u7b2c\u4e09\u7ae0_\u5fae\u8edf\u7684\u6050\u61fc\u8207 Xbox \u7684\u8a95\u751f",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u4e09\u7ae0_\u5fae\u8edf\u7684\u6050\u61fc\u8207 Xbox \u7684\u8a95\u751f"},next:{title:"Chapter 5: The Wild Growth of AI and Wintel's Blind Spot",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u4e94\u7ae0_AI\u7684\u91ce\u883b\u751f\u9577\u8207Wintel\u7684\u76f2\u5340_v2"}},h={},l=[{value:"I. Motive for the Crime",id:"i-motive-for-the-crime",level:2},{value:"II. Forging the Weapon \u2014 The Wrong One",id:"ii-forging-the-weapon--the-wrong-one",level:2},{value:"III. A Contract Destined to Fail",id:"iii-a-contract-destined-to-fail",level:2},{value:"IV. A Phone Call That Shouldn&#39;t Have Been Made",id:"iv-a-phone-call-that-shouldnt-have-been-made",level:2},{value:"V. Six Months of Rebirth",id:"v-six-months-of-rebirth",level:2},{value:"VI. The Interest on the Charity",id:"vi-the-interest-on-the-charity",level:2},{value:"VII. Closing Arguments",id:"vii-closing-arguments",level:2},{value:"VIII. The Loot is Still Being Divided",id:"viii-the-loot-is-still-being-divided",level:2}];function d(e){const t={em:"em",h1:"h1",h2:"h2",header:"header",hr:"hr",img:"img",p:"p",strong:"strong",...(0,i.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"chapter-4-segas-five-million-dollar-mercy",children:"Chapter 4: Sega's Five-Million-Dollar Mercy"})}),"\n",(0,a.jsx)(t.p,{children:"In 2025, a machine learning engineer complained on his company's Slack: training a mid-sized language model requires eight NVIDIA H100s running for three weeks. One H100 costs over $30,000. His company waited in line for six months just to get the shipment. Every company in the world that wants to do AI is waiting in that exact same line."}),"\n",(0,a.jsx)(t.p,{children:"He writes his models in PyTorch. Beneath PyTorch is CUDA. CUDA only runs on NVIDIA GPUs. It's not that he hasn't tried AMD's ROCm\u2014the documentation is incomplete, the community is dead, and the ecosystem is barren. It's not that he hasn't heard of Google's TPU\u2014but that's Google's own hardware; outsiders can rent the compute, but they can't get the chips."}),"\n",(0,a.jsx)(t.p,{children:"He knows very well in his heart: the entire AI industry is being choked by the throat by a single company. But he doesn't find this surprising. NVIDIA has been making GPUs for thirty years, and its technical accumulation is bottomless\u2014this kind of monopoly is built on time and capability; it's perfectly natural."}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.strong,{children:"No, it isn't."})}),"\n",(0,a.jsx)(t.p,{children:"NVIDIA almost ceased to exist in 1996."}),"\n",(0,a.jsx)(t.p,{children:"That year, it had less than six months of cash left. Its core technical roadmap had been proven to be a dead end. Its only major client was preparing to terminate their contract. According to the standard Silicon Valley script, it should have quietly disappeared that year, becoming just another name among the dozens of graphics card companies that perished in the mid-nineties."}),"\n",(0,a.jsx)(t.p,{children:"It didn't disappear. Because a Japanese man whose own company was also dying did something that violated every business textbook."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"i-motive-for-the-crime",children:"I. Motive for the Crime"}),"\n",(0,a.jsx)(t.p,{children:"In January 1993, three engineers sat down in a Denny's diner in San Jose, California, and decided to found a company. Thirty-year-old Jensen Huang was the youngest among them. He had been at both LSI Logic and AMD, doing chip design as well as technical marketing\u2014this kind of dual-role experience spanning engineering and business wasn't unheard of in Silicon Valley at the time, but it wasn't exactly common either. The other two co-founders, Chris Malachowsky and Curtis Priem, were both hardware engineers from Sun Microsystems."}),"\n",(0,a.jsxs)(t.p,{children:["What they wanted to do was, in today's language, very simple: make a graphics card that could make PC game visuals look beautiful. In 1993, 3D graphics on the PC was still a wasteland. Carmack, mentioned in the previous chapter, was using pure CPU power to brute-force render every pixel of ",(0,a.jsx)(t.em,{children:"Doom"}),"; consumer-grade 3D acceleration hardware was virtually non-existent in the market. The opportunity Jensen Huang saw was this: if they could make a chip specifically for processing 3D calculations, game visuals would take a qualitative leap, and the number of players willing to pay for this was exploding."]}),"\n",(0,a.jsx)(t.p,{children:"But at that diner table, Jensen Huang made a decision\u2014a decision that almost buried the entire company."}),"\n",(0,a.jsx)(t.p,{children:"He chose a technical path completely different from everyone else's."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"ii-forging-the-weapon--the-wrong-one",children:"II. Forging the Weapon \u2014 The Wrong One"}),"\n",(0,a.jsx)(t.p,{children:"In 1995, NVIDIA launched its first product: the NV1."}),"\n",(0,a.jsx)(t.p,{children:"The NV1's design ambition was immense. It wasn't just a graphics card\u2014it integrated 2D graphics, 3D rendering, audio processing, and even a port for the Sega Saturn controller. One card replacing three. To consumers, this sounded beautiful."}),"\n",(0,a.jsx)(t.p,{children:"But the NV1 had a fundamental problem hidden deep within its 3D rendering engine."}),"\n",(0,a.jsx)(t.p,{children:"At the time, all 3D graphics systems\u2014OpenGL, the upcoming Direct3D, Hollywood workstations, and every 3D game in development\u2014used the exact same basic unit: the triangle. Slice the surface of any 3D object into enough triangles, map a texture to each triangle, stitch them together, and you have a passable model. The triangle was the universal language of the entire 3D graphics industry; from academic papers to hardware circuits, everyone was designing around triangles."}),"\n",(0,a.jsx)(t.p,{children:"NVIDIA didn't use triangles."}),"\n",(0,a.jsx)(t.p,{children:'The technical architecture led by Curtis Priem chose a method called "quadratic texture mapping"\u2014replacing triangles with quadrilaterals, and then using mathematical curves to bend the surfaces of the quadrilaterals. In theory, this method could draw smoother curved surfaces using fewer geometric units. A sphere might require hundreds of triangles to construct; theoretically, a quadrilateral system could define it with just four.'}),"\n",(0,a.jsx)(t.p,{children:"From a purely mathematical perspective, quadrilaterals have their elegance. But engineering is not math."}),"\n",(0,a.jsxs)(t.p,{children:["The problem was: no software was written for quadrilaterals. No 3D modeling tools outputted quadrilaterals. No game engines supported quadrilaterals. Even more fatally, when Microsoft officially released the Direct3D specification in 1996, it explicitly mandated\u2014",(0,a.jsx)(t.strong,{children:"only triangles are supported"}),"."]}),"\n",(0,a.jsx)(t.p,{children:"Overnight, NVIDIA's entire technical architecture became an isolated island."}),"\n",(0,a.jsx)(t.p,{children:"The NV1 failed miserably in the market. It was too expensive, its audio quality was mediocre, its 2D speed was inferior to dedicated 2D graphics cards, and its only killer feature\u20143D acceleration\u2014was almost unsupported by games because it was incompatible with all standards. The only 3D games that could run on the NV1 were a few old titles ported from the Sega Saturn\u2014because the Saturn also happened to render using quadrilaterals."}),"\n",(0,a.jsx)(t.p,{children:"This was the foreshadowing of Sega's entry."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"iii-a-contract-destined-to-fail",children:"III. A Contract Destined to Fail"}),"\n",(0,a.jsx)(t.p,{children:"The relationship between Sega and NVIDIA began with those few Saturn game ports on the NV1. The NV1's quadrilateral architecture was similar to the Saturn's rendering method, making porting relatively easy\u2014this was a unique selling point in the PC market of 1995, even if it didn't sell well."}),"\n",(0,a.jsx)(t.p,{children:'But Sega saw another possibility. It was planning its next-generation console\u2014internally codenamed including "Saturn V08," the predecessor to what would later become the Dreamcast. Sega needed a graphics processing chip. NVIDIA had proven its ability to design media acceleration chips, and the quadrilateral architecture was at least compatible with Sega\'s past hardware DNA.'}),"\n",(0,a.jsx)(t.p,{children:"In mid-1995, Sega signed a contract with NVIDIA: NVIDIA would develop the graphics chip for Sega's next-generation console, codenamed NV2."}),"\n",(0,a.jsx)(t.p,{children:"NV2 continued the NV1's quadrilateral path."}),"\n",(0,a.jsx)(t.p,{children:"This decision was not entirely unreasonable at the time. In 1995, the standard war between triangles and quadrilaterals was not yet completely settled. Direct3D was still in its first version, OpenGL primarily ran on workstations, and 3D acceleration in the PC gaming market was just getting started. Priem and Huang believed that if the NV2 could succeed on the Dreamcast, quadrilaterals had a chance to become a standard parallel to triangles."}),"\n",(0,a.jsx)(t.p,{children:"But they underestimated one thing: Microsoft's speed."}),"\n",(0,a.jsxs)(t.p,{children:["In 1996, Direct3D entered its rapid iteration phase. Every new version strengthened the feature set for triangle rendering. More importantly, ",(0,a.jsx)(t.strong,{children:"Microsoft controlled Windows"}),"\u2014the previous chapter already explained how lethal this card is. All graphics card manufacturers who wanted to make PC games had to support Direct3D, and Direct3D only spoke the language of triangles. 3dfx's Voodoo, ATI's Rage, Matrox, Rendition\u2014the entire market was rotating around triangles as its axis."]}),"\n",(0,a.jsx)(t.p,{children:"And NVIDIA was still trapped on the island of quadrilaterals, holding a contract designed for quadrilaterals."}),"\n",(0,a.jsx)(t.p,{children:"The development of the NV2 lasted over a year. Prototype chips were sent to Sega for demonstration. The demonstration failed. Inside Sega\u2014especially the arcade division AM2\u2014voices began loudly opposing the quadrilateral path, demanding a switch to triangles. Inside NVIDIA, arguments among the co-founders were also heating up. Priem insisted that quadrilaterals had a technical advantage; Huang began to waver."}),"\n",(0,a.jsx)(t.p,{children:"By mid-1996, Jensen Huang made a painful judgment."}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.strong,{children:"Continue making the NV2, deliver a quadrilateral chip, and fulfill the contract\u2014but this chip won't be compatible with Direct3D, effectively disconnecting it from the entire PC ecosystem. NVIDIA will have revenue, but no future."})}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.strong,{children:"Or, abandon the NV2, admit the technical roadmap was a mistake, and pivot immediately to triangles\u2014but what about the contract? What about Sega's money? The company's remaining cash won't last six months."})}),"\n",(0,a.jsx)(t.p,{children:'Jensen Huang later recalled this moment on multiple occasions. His exact words were: "Whichever path we took, we were going to go out of business."'}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"iv-a-phone-call-that-shouldnt-have-been-made",children:"IV. A Phone Call That Shouldn't Have Been Made"}),"\n",(0,a.jsx)(t.p,{children:"Jensen Huang flew to meet Shoichiro Irimajiri."}),"\n",(0,a.jsx)(t.p,{children:"Shoichiro Irimajiri was the CEO of Sega of America at the time. His resume was much thicker than most gaming industry executives\u2014in his early years, he worked as an engineer at Honda Motors, participated in the development of F1 racing engines, later moved into management, and was ultimately poached by Sega. He was the kind of person rarely seen in corporations: an executive who had gotten his hands dirty. He had seen engines blow cylinders, and he had seen product lines get axed. He understood technical risk not because he had read case studies, but because he had personally built things that exploded."}),"\n",(0,a.jsx)(t.p,{children:"Huang didn't bring a progress report. He brought a sentence that almost no one in Silicon Valley dares to say to a client\u2014"}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.strong,{children:"We cannot build what you want."})}),"\n",(0,a.jsx)(t.p,{children:"The NV2's technical roadmap was a dead end. Quadrilaterals were not going to become the industry standard, and continuing would only waste both Sega's and NVIDIA's time. NVIDIA had to abandon this path and immediately pivot to triangles, or the company would die."}),"\n",(0,a.jsx)(t.p,{children:"Then he said something even more unbelievable\u2014"}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.strong,{children:"But we need you to pay us."})}),"\n",(0,a.jsx)(t.p,{children:"NVIDIA had failed to deliver the product required by the contract. According to normal business logic, Sega should have terminated the contract, demanded the money back, and perhaps even sued for damages. NVIDIA was the first to breach the contract; Sega had a hundred reasons not to pay a single cent."}),"\n",(0,a.jsx)(t.p,{children:"And Sega itself wasn't exactly a wealthy company. The Saturn was being crushed globally by the PlayStation, barely holding on in the Japanese market, and almost completely defeated in the West. Every cent of cash Sega had should have been used to prepare for the launch of the Dreamcast\u2014finding a new chip supplier, signing new game development contracts, doing marketing. Paying a supplier who couldn't deliver the goods is the wrong answer in any management textbook."}),"\n",(0,a.jsx)(t.p,{children:"Shoichiro Irimajiri listened to what Jensen Huang had to say."}),"\n",(0,a.jsx)(t.p,{children:"He chose the answer that wasn't in the textbook."}),"\n",(0,a.jsx)(t.p,{children:"Sega invested $5 million into NVIDIA. Not paying a penalty fee, but an investment\u2014buying shares in NVIDIA. The reason Irimajiri was later quoted as giving was simple to the point of naive: he thought Jensen Huang was a trustworthy young man."}),"\n",(0,a.jsx)(t.p,{children:'Huang\'s subsequent recollection was: "His understanding and generosity gave us six months to live."'}),"\n",(0,a.jsx)(t.p,{children:"Six months."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"v-six-months-of-rebirth",children:"V. Six Months of Rebirth"}),"\n",(0,a.jsx)(t.p,{children:"After getting Sega's money, Jensen Huang did three things."}),"\n",(0,a.jsx)(t.p,{children:'First, he slashed the company\'s headcount from over a hundred people to thirty-five. Everyone who stayed was an engineer. No marketing, no administration, no roles unrelated to "getting the chip designed."'}),"\n",(0,a.jsx)(t.p,{children:"Second, he terminated all development related to quadrilaterals. The NV2's code, the NV1's architecture, Priem's two-plus years of hard work\u2014everything went to zero. The new chip's codename was NV3. The architecture started from the very first line of code, speaking only the language of triangles, born solely for Direct3D."}),"\n",(0,a.jsx)(t.p,{children:"Third, he used the remaining money to buy a hardware emulator."}),"\n",(0,a.jsx)(t.p,{children:"This emulator was the most crucial move in the entire gamble. The traditional chip design process is: design the circuit, send it to the foundry for manufacturing, get the finished product back for testing, find bugs, modify the design, and send it back for manufacturing\u2014one cycle takes at least one to two years. NVIDIA didn't have two years. It didn't even have one year. Jensen Huang used the hardware emulator to run the entire chip's tests in a software environment, fixing all the bugs first before sending it to manufacturing\u2014\"measure twice, cut once.\" The entire design cycle was compressed to about seven months."}),"\n",(0,a.jsx)(t.p,{children:"In April 1997, the NV3 was officially announced. It had a new name: RIVA 128."}),"\n",(0,a.jsxs)(t.p,{children:["The RIVA 128 was not a great graphics card. Its drivers were notoriously rough in the early days, its OpenGL support was incomplete, and its 2D image quality was merely passable. But it achieved one thing the NV1 never did\u2014",(0,a.jsx)(t.strong,{children:"it ran Direct3D, and it ran it fast and stable."})]}),"\n",(0,a.jsx)(t.p,{children:"128-bit memory bandwidth, a 100 MHz core clock, 1.5 million triangles per second\u2014these numbers weren't the absolute best in the PC graphics card market of 1997, but they were enough to enter the top tier. More importantly, its price was cheaper than 3dfx's Voodoo, and because 2D and 3D were on the same card, consumers didn't need to slot two cards at once like they did with the Voodoo."}),"\n",(0,a.jsx)(t.p,{children:"In January 1998, NVIDIA shipped its one-millionth RIVA 128."}),"\n",(0,a.jsx)(t.p,{children:"In March of the same year, NVIDIA signed a strategic partnership agreement with TSMC."}),"\n",(0,a.jsx)(t.p,{children:"This point in time is worth pausing to look at\u2014because it is the foreshadowing for Chapter 8. The NVIDIA of 1998 was still a small company that had just come back to life, and TSMC was not yet the irreplaceable entity it is today. But from this moment on, every single chip NVIDIA designed would be manufactured by TSMC. Twenty-six years later, NVIDIA's H100\u2014the chip that drove the training of ChatGPT, Claude, and Gemini\u2014still comes from TSMC's production lines. The starting point of this supply chain is in that 1998 contract."}),"\n",(0,a.jsx)(t.p,{children:"And the reason that contract existed was because NVIDIA survived 1996."}),"\n",(0,a.jsx)(t.p,{children:"The reason NVIDIA survived 1996 was because a Japanese man paid $5 million."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"vi-the-interest-on-the-charity",children:"VI. The Interest on the Charity"}),"\n",(0,a.jsx)(t.p,{children:"The subsequent fate of Shoichiro Irimajiri forms a cruel contrast with the company he saved."}),"\n",(0,a.jsx)(t.p,{children:"In 1998, he was promoted to President of Sega worldwide. Under his supervision, the Dreamcast adopted the PowerVR chip, a collaboration between NEC and VideoLogic\u2014replacing the NV2 that NVIDIA had abandoned. The Dreamcast launched first at the end of 1998, featuring ahead-of-its-time online capabilities and stunning visuals."}),"\n",(0,a.jsx)(t.p,{children:"But the PS2 arrived."}),"\n",(0,a.jsx)(t.p,{children:"In March 2000, Sony's PlayStation 2 launched in Japan, with lines winding around several blocks. Ken Kutaragi's phrase \"the home computer of the twenty-first century\"\u2014the press conference mentioned in the previous chapter that kept Gates awake\u2014was becoming a reality. The PS2 sold over ten million units in its first year. Dreamcast sales began to plummet off a cliff."}),"\n",(0,a.jsx)(t.p,{children:"In 2000, Shoichiro Irimajiri resigned from his position as President. Sega suffered losses for the third consecutive year."}),"\n",(0,a.jsx)(t.p,{children:"In March 2001, Sega announced its exit from the console hardware market. Dreamcast production ceased. A company that had been making game consoles since 1983 left the hardware battlefield forever under the pressure of the PS2."}),"\n",(0,a.jsx)(t.p,{children:"Before exiting, Sega sold the shares it held in NVIDIA. The stock originally bought for $5 million was sold for $15 million. With this money, Sega slightly alleviated the financial pressure of exiting the console business."}),"\n",(0,a.jsx)(t.p,{children:"$15 million. A triple return. By venture capital standards, this was a good deal."}),"\n",(0,a.jsx)(t.p,{children:"But if Sega hadn't sold\u2014"}),"\n",(0,a.jsx)(t.p,{children:"In 2025, NVIDIA's market capitalization exceeds $3 trillion. That original $5 million investment, converted by share price, would be worth tens of billions of dollars."}),"\n",(0,a.jsx)(t.p,{children:"Sega didn't wait for that day. It couldn't afford to wait."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"vii-closing-arguments",children:"VII. Closing Arguments"}),"\n",(0,a.jsx)(t.p,{children:"This chapter is not a story about investment foresight. It is a story about contingency."}),"\n",(0,a.jsx)(t.p,{children:"Let's calculate this bill clearly\u2014"}),"\n",(0,a.jsx)(t.p,{children:'Shoichiro Irimajiri gave NVIDIA $5 million in 1996. That money kept NVIDIA alive for six months. In those six months, NVIDIA created the RIVA 128, pivoted to triangle rendering, and tapped into the Direct3D ecosystem. In 1998, NVIDIA signed with TSMC. In 1999, the GeForce 256 was released\u2014the industry\'s first chip to be called a "GPU." In 2006, Jensen Huang bet on CUDA, turning the GPU from a game engine into a general-purpose parallel computing platform. In 2012, AlexNet proved that deep learning needed GPUs. In 2022, the H100 drove the training of ChatGPT.'}),"\n",(0,a.jsx)(t.p,{children:'In the middle of this causal chain, there are countless nodes that could have broken. But the most fragile one\u2014the one closest to going to zero\u2014was the moment in 1996 when Shoichiro Irimajiri said "yes."'}),"\n",(0,a.jsx)(t.p,{children:'He wasn\'t making an investment decision. The company in front of him had failed products, a wrong technical roadmap, cash hitting rock bottom, and no deliverable results. Every number said "no." He said "yes" because\u2014according to the consensus of all later reporting\u2014he felt Jensen Huang was an honest man who deserved one more chance.'}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.strong,{children:"Here appears a variation of the pattern this book tracks."})}),"\n",(0,a.jsx)(t.p,{children:"The patterns in the previous two chapters were offensive: DirectX used convenience to attract developers, then used the lock-in effect to bind the ecosystem (Chapter 2); Xbox used losses to block the flank and drain the opponent's ambition (Chapter 3). These are the strategic actions of large corporations\u2014rational, calculable, with ROI models."}),"\n",(0,a.jsxs)(t.p,{children:["The pattern in Chapter 4 is contingent: ",(0,a.jsx)(t.strong,{children:"Before offensive lock-in can occur, someone must first survive. And surviving, sometimes, relies not on strategy, but on a single person making a decision in a single moment with no rational basis."})]}),"\n",(0,a.jsxs)(t.p,{children:["NVIDIA's subsequent CUDA monopoly\u2014which will be expanded upon in Chapter 7\u2014is textbook platform lock-in. But the prerequisite for the CUDA monopoly is that NVIDIA re-entered the triangle world in 1997, became the definer of the GPU in 1999, and had enough market position in 2006 to place a ten-year bet. ",(0,a.jsx)(t.strong,{children:"And the prerequisite for all of this was a $5 million charity."})]}),"\n",(0,a.jsx)(t.p,{children:"Business textbooks will tell you: monopoly is a systemic engineering project. Correct. But the first brick of a systemic engineering project is sometimes a person's intuition, a meal that shouldn't have been eaten, or a phone call that shouldn't have been made."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"viii-the-loot-is-still-being-divided",children:"VIII. The Loot is Still Being Divided"}),"\n",(0,a.jsx)(t.p,{children:"Back to the machine learning engineer complaining about the H100 queue in 2025 at the beginning."}),"\n",(0,a.jsx)(t.p,{children:"He is being choked by the throat by NVIDIA. The causal chain for this did not start with CUDA, did not start with GeForce, and didn't even start with the founding of NVIDIA. Its true starting point was a Japanese game company executive who, at the moment his own company was about to sink, threw his last life preserver to someone else."}),"\n",(0,a.jsxs)(t.p,{children:["The absurdity of this bill is: ",(0,a.jsx)(t.strong,{children:"Sega signed a graphics card contract to build a game console; the contract failed, and Sega chose to pay rather than collect debt; that money saved a company; that company spent twenty years building the monopoly that today chokes the throat of the entire AI industry."})]}),"\n",(0,a.jsx)(t.p,{children:"Is Sega a victim? Not entirely. It got a triple return, just sold too early. Is NVIDIA a beneficiary? Unquestionably. But the true victims are every AI researcher locked in by CUDA in 2025\u2014they are paying forward interest on a charity from 1996."}),"\n",(0,a.jsx)(t.p,{children:"And after Sega exited the console battlefield, the position it vacated was coincidentally filled by an American company. That company just made its appearance in the previous chapter\u2014it used an NVIDIA chip to build a living room console running Windows."}),"\n",(0,a.jsx)(t.p,{children:"The GPU inside the Xbox, codenamed NV2A, was based on the GeForce 3 architecture. The ancestor of the GeForce 3 was the RIVA 128. The RIVA 128 existed because of Shoichiro Irimajiri's $5 million."}),"\n",(0,a.jsx)(t.p,{children:"The lines have connected."}),"\n",(0,a.jsx)(t.p,{children:"But the lines aren't finished connecting. NVIDIA got another contract in 1999\u2014this time from Microsoft. The GPU for the Xbox was supplied by NVIDIA. This contract gave NVIDIA its first taste of the console market, and also taught it its first lesson about the profit structure of console contracts\u2014Microsoft demanded year-over-year price cuts, NVIDIA refused, and the two sides fell out. The Xbox 360 switched to an ATI chip."}),"\n",(0,a.jsx)(t.p,{children:"NVIDIA thereafter exited the console GPU market, concentrating all its firepower on PC graphics cards."}),"\n",(0,a.jsxs)(t.p,{children:['This experience of being "forced out of the console market by Microsoft" paradoxically turned out to be NVIDIA\'s luck\u2014because it forced Jensen Huang to ponder a question: ',(0,a.jsx)(t.strong,{children:"Besides drawing games, what else can a GPU do?"})]}),"\n",(0,a.jsx)(t.p,{children:"The answer to that question was called CUDA. It will appear in Chapter 7."}),"\n",(0,a.jsx)(t.p,{children:"But before arriving at Chapter 7, the story must first shift to another timeline. The DirectX lock-in discussed in Chapter 2 began producing a side effect Microsoft hadn't foreseen by the 2010s\u2014people who needed freedom started leaving Windows. Scientific researchers, server administrators, and those who would later train AI models, all flocked to Linux."}),"\n",(0,a.jsx)(t.p,{children:"And exactly while these people were flocking to Linux, Intel made a mistake as fatal as NVIDIA's NV1\u2014only Intel didn't have a Shoichiro Irimajiri to save it."}),"\n",(0,a.jsx)(t.p,{children:"The name of that mistake was Larrabee."}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.img,{src:n(6338).A+"",width:"1200",height:"655"})})]})}function c(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},6338(e,t,n){n.d(t,{A:()=>a});const a=n.p+"assets/images/ch04_en-1ec9e78209053cbb839d86c5100cba0b.png"},8453(e,t,n){n.d(t,{R:()=>r,x:()=>o});var a=n(6540);const i={},s=a.createContext(i);function r(e){const t=a.useContext(s);return a.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function o(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:r(e.components),a.createElement(s.Provider,{value:t},e.children)}}}]);